#include <stdio.h>
#include <ctype.h>

#define MAX_TOKEN_LENGTH 100

char token[MAX_TOKEN_LENGTH];
int token_length = 0;

void token_recognition(char *input_stream) {
 while (*input_stream != '\0') {
 if (isdigit(*input_stream)) {
 // integer literal
 while (isdigit(*input_stream)) {
 token[token_length++] = *input_stream;
 input_stream++;
 }
 token[token_length] = '\0';
 printf("Integer literal: %s\n", token);
 token_length = 0;
 } else if (isalpha(*input_stream) || *input_stream == '_') {
 // identifier
 while (isalnum(*input_stream) || *input_stream == '_') {
 token[token_length++] = *input_stream;
 input_stream++;
 }
 token[token_length] = '\0';
 printf("Identifier: %s\n", token);
 token_length = 0;
 } else {
 // other characters
 input_stream++;
 }
 }
}

int main() {
 char input_stream[] = "sum=42+val;";
 token_recognition(input_stream);
 return 0;
}
